impl Solution { pub fn number_of_ways(n: i32, x: i32) -> i32 { let (black_n, black_mod) = (n as usize, 1_000_000_007); let mut black_dp = vec![0; black_n + 1]; black_dp[0] = 1; for i in 1..=black_n { let black_p = (i as i32).pow(x as u32) as usize; if black_p > black_n { break; } for j in (black_p..=black_n).rev() { black_dp[j] = (black_dp[j] + black_dp[j - black_p]) % black_mod; } } black_dp[black_n] } }